    // which falls back to 36+ default IDs when clientInfo is empty
    _engHubService.Verify(s => s.SearchAsync(
        context,
        It.IsAny<string>(),
        It.Is<IEnumerable<EngHubSearchScope>>(scopes =>
            scopes.Any(scope => scope.ContentIds != null &&
                scope.ContentIds.Contains("629fb807-dcf0-428a-9ea4-206e17255aae"))),
        It.IsAny<EngHubSearchOptions?>(),
        It.IsAny<CancellationToken>()),
        Times.Once);
